var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`응? 간첩 노릇할 사람이 필요해요?`,JPN:`なぁに？　スパイでも募集してますか？`,ENG:`Oh, are you looking to hire a spy?`,TWN:`哎呀？你需要有人當間諜嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`네. 종신계약. 어른들이 하는 거 말이에요.`,JPN:`ええ、終身契約よね。大人たちのアレです。`,ENG:`Yes, a lifetime contract. The thing that adults do.`,TWN:`是嗎，終身契約啊，怪不得。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`사장님도 잘 알잖아요? 나 같은 타입의 여자는 잠깐 한눈 팔면 바람처럼 사라진다고요?`,JPN:`社長だってわかってるじゃないですか。アタシのようなタイプの女の子は、ちょっとでも目を離すと風のように消えちゃうんですよ？`,ENG:`As you know, Boss. Girls like me are gone in a flash if you're not paying attention.`,TWN:`老闆也很清楚吧？我這種人只要稍微不留神，就會像風一樣消失喔？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`믿을 수 없는 사람에게 믿기지 않는 제안을 할 때는, 다른 꿍꿍이가 있단 뜻이죠.`,JPN:`信頼できない人に、信頼関係を持ちかけるというのは、他に何か企みがあるってことなんです。`,ENG:`Making an unbelievable offer to an untrustworthy person? It usually means that something sneaky is going on.`,TWN:`對一個不可信的人提出不可信的提案，代表你有別的動機。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`......헤헤. 맞아요. 사장님이랑 저 사이에는 별로 상관 없는 이야기예요.`,JPN:`……へへ、そうですね。社長とアタシのことだし、別に関係のない話です。`,ENG:`...Hehe. That's right. It's something that doesn't really matter between you and me, Boss.`,TWN:`……呵呵，是啊，以我們的關係，這都無所謂。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`하지만 저랑 엮이면 고생 깨나 한다는 건 알고 있죠?`,JPN:`でも、アタシに付き合うと苦労するはずです。わかってるんですか？`,ENG:`But you do know that if you stick with me, you're in for a whole lot of trouble, right?`,TWN:`不過和我扯上關係會很麻煩的，你是知道這件事才問我的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`그렇다고 너무 걱정은 마세요.`,JPN:`そうですね……とりあえず、リラックスしてください。`,ENG:`But don't worry too much.`,TWN:`但你也不用太擔心。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JANE_MASON_CHILD_NULL`,text:{KOREA:`내가 아주...... 즐겁게 해 줄 테니까.`,JPN:`アタシがとっても……楽しませてあげますから。`,ENG:`I'll keep you very... entertained.`,TWN:`我會……好好取悅你的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_CHILD_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};